graphql.query:
mutation Login($username: String!, $password: String!) {
  login(username: $username, password: $password) {
    access_token
    token_type
    expires_in
    refresh_token
  }
}

query Me {
  me {
    id
    name
    username
    email
  }
}

query Employees($first: Int!, $page: Int) {
  employees(first: $first, page: $page) {
    data {
      id
      first_name
      last_name
      email
      phone
      address
      salary
      created_at
      updated_at
    }
    paginatorInfo {
      count
      currentPage
      lastPage
      perPage
      total
      hasMorePages
    }
  }
}

query Employee($id: ID!) {
  employee(id: $id) {
    id
    first_name
    last_name
    email
    phone
    address
    salary
    created_at
    updated_at
  }
}

mutation UpdateEmployee($input: UpdateEmployeeInput!) {
  updateEmployee(input: $input) {
    id
    first_name
    last_name
    email
    phone
    address
    salary
    updated_at
  }
}

mutation DeleteEmployee($id: ID!) {
  deleteEmployee(id: $id) {
    id
    first_name
    last_name
  }
}

query ImportStatus($id: String!) {
  importStatus(id: $id) {
    status
    processed
    total
  }
}
